export function getAllLessons(): Lesson[] {
  return CCNA_CURRICULUM.flatMap(module => module.lessons)
}

export function getTotalDuration(): number {
  return getAllLessons().reduce((total, lesson) => total + lesson.duration, 0)
}

export function getLessonById(id: string): Lesson | undefined {
  return getAllLessons().find(lesson => lesson.id === id)
}

export function getModuleById(id: string): Module | undefined {
  return CCNA_CURRICULUM.find(module => module.id === id)
}
